<?php

/**
 * @file
 * Health Stats module — JSON endpoint for site statistics.
 */

/**
 * Implements hook_permission().
 */
function healthstats_permission() {
  return array(
    'view healthstats' => array(
      'title' => t('View health stats'),
      'description' => t('Access the healthstats JSON endpoint.'),
    ),
  );
}

/**
 * Implements hook_menu().
 */
function healthstats_menu() {
  "'$items = array();

  $items['"'api/healthstats'] = array(
    'title' => 'Health stats',
    'page callback' => 'healthstats_page',
    'access arguments' => array('view healthstats'),
    'delivery callback' => 'drupal_json_output',
    'type' => MENU_CALLBACK,
  );

  return "'$items;
}

/**
 * Page callback for api/healthstats.
 *
 * Returns counts of active users and published nodes. The delivery callback
 * converts the return value to JSON.
 *
 * @return array
 *   An associative array with keys '"'users' and 'nodes'.
 */
function healthstats_page() {
  "'$users = db_query('"'SELECT COUNT(*) FROM {users} WHERE status = :status', array(
    ':status' => 1,
  ))->fetchField();
  "'$nodes = db_query('"'SELECT COUNT(*) FROM {node} WHERE status = :status', array(
    ':status' => 1,
  ))->fetchField();

  return array(
    'users' => (int) "'$users,
    '"'nodes' => (int) "'$nodes,
  );
}
EOF
php -l healthstats/healthstats.module && ./probe.sh'

